import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { productsAPI, ordersAPI } from '../services/api';
import { useSocket } from '../contexts/SocketContext';
import { useAuth } from '../contexts/AuthContext';
import { 
  ShoppingCart, 
  TrendingUp, 
  TrendingDown, 
  Package, 
  Clock, 
  BarChart3,
  Star,
  Truck,
  Shield,
  ArrowLeft
} from 'lucide-react';
import toast from 'react-hot-toast';

const ProductDetail = () => {
  const { id } = useParams();
  const { user } = useAuth();
  const { joinProductRoom, leaveProductRoom } = useSocket();

  const [product, setProduct] = useState(null);
  const [demandMetrics, setDemandMetrics] = useState(null);
  const [pricingHistory, setPricingHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [quantity, setQuantity] = useState(1);
  const [currentPrice, setCurrentPrice] = useState(null);

  useEffect(() => {
    fetchProductData();
    joinProductRoom(id);

    return () => {
      leaveProductRoom(id);
    };
  }, [id]);

  const fetchProductData = async () => {
    try {
      setLoading(true);

      const [productResponse, demandResponse, historyResponse] = await Promise.all([
        productsAPI.getById(id),
        productsAPI.getDemandMetrics(id),
        productsAPI.getPricingHistory(id, 10)
      ]);

      setProduct(productResponse.data);
      setCurrentPrice(productResponse.data.current_price);
      setDemandMetrics(demandResponse.data);
      setPricingHistory(historyResponse.data);
    } catch (error) {
      console.error('Error fetching product data:', error);
      toast.error('Failed to load product details');
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(price);
  };

  const getPriceChangePercentage = (product) => {
    const change = (product.current_price - product.base_price) / product.base_price * 100;
    return change;
  };

  const handleAddToCart = async () => {
    if (!user) {
      toast.error('Please login to add items to cart');
      return;
    }

    if (quantity > product.stock_quantity) {
      toast.error('Not enough stock available');
      return;
    }

    try {
      // Create a temporary order for cart functionality
      const orderData = {
        items: [{
          product_id: product.id,
          quantity: quantity,
          unit_price: currentPrice,
          total_price: currentPrice * quantity
        }],
        shipping_address: 'Default address'
      };

      await ordersAPI.create(orderData);
      toast.success(`${quantity} ${product.name} added to cart!`);
    } catch (error) {
      console.error('Error adding to cart:', error);
      toast.error('Failed to add to cart');
    }
  };

  const handleQuantityChange = (newQuantity) => {
    const maxQuantity = product?.stock_quantity || 0;
    if (newQuantity >= 1 && newQuantity <= maxQuantity) {
      setQuantity(newQuantity);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!product) {
    return (
      <div className="text-center py-12">
        <h3 className="text-lg font-medium text-gray-900 mb-2">Product not found</h3>
        <Link to="/products" className="text-primary-600 hover:text-primary-700">
          Back to Products
        </Link>
      </div>
    );
  }

  const priceChange = getPriceChangePercentage(product);
  const isInStock = product.stock_quantity > 0;

  return (
    <div className="max-w-7xl mx-auto space-y-8">
      {/* Back Button */}
      <Link 
        to="/products" 
        className="inline-flex items-center space-x-2 text-gray-600 hover:text-primary-600 transition-colors"
      >
        <ArrowLeft className="h-4 w-4" />
        <span>Back to Products</span>
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Product Image */}
        <div className="space-y-4">
          <div className="bg-gray-100 rounded-lg overflow-hidden">
            <img
              src={product.image_url || `https://picsum.photos/seed/${product.id}/600/600.jpg`}
              alt={product.name}
              className="w-full h-96 object-cover"
            />
          </div>

          {/* Stock Status */}
          <div className="flex items-center justify-between p-4 bg-white rounded-lg shadow-soft">
            <div className="flex items-center space-x-2">
              <Package className="h-5 w-5 text-gray-400" />
              <span className="text-sm font-medium text-gray-900">
                {isInStock ? `${product.stock_quantity} in stock` : 'Out of stock'}
              </span>
            </div>
            <span className={`px-3 py-1 text-xs font-medium rounded-full ${
              isInStock 
                ? 'bg-success-100 text-success-800' 
                : 'bg-danger-100 text-danger-800'
            }`}>
              {isInStock ? 'Available' : 'Unavailable'}
            </span>
          </div>
        </div>

        {/* Product Details */}
        <div className="space-y-6">
          {/* Title and Category */}
          <div>
            <div className="flex items-center space-x-2 mb-2">
              <span className="text-sm text-primary-600 font-medium">
                {product.category_name}
              </span>
              <span className="text-gray-400">•</span>
              <span className="text-sm text-gray-500">SKU: {product.sku}</span>
            </div>
            <h1 className="text-3xl font-bold text-gray-900 mb-4">{product.name}</h1>
            <p className="text-gray-600 leading-relaxed">{product.description}</p>
          </div>

          {/* Pricing */}
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center justify-between mb-4">
              <div>
                <div className="flex items-center space-x-3">
                  <p className="text-3xl font-bold text-gray-900">
                    {formatPrice(currentPrice || product.current_price)}
                  </p>
                  {product.current_price !== product.base_price && (
                    <div className="flex items-center space-x-2">
                      <p className="text-lg text-gray-500 line-through">
                        {formatPrice(product.base_price)}
                      </p>
                      <div className="flex items-center space-x-1">
                        {priceChange > 0 ? (
                          <TrendingUp className="h-4 w-4 text-success-600" />
                        ) : (
                          <TrendingDown className="h-4 w-4 text-danger-600" />
                        )}
                        <span className={`text-sm font-medium ${
                          priceChange > 0 ? 'text-success-600' : 'text-danger-600'
                        }`}>
                          {Math.abs(priceChange).toFixed(1)}% {priceChange > 0 ? 'increase' : 'decrease'}
                        </span>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* Competitor Price Comparison */}
            {product.avg_competitor_price && (
              <div className="pt-4 border-t border-gray-200">
                <p className="text-sm text-gray-600 mb-2">Market Comparison</p>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-500">Average competitor price</span>
                  <span className="font-medium text-gray-900">
                    {formatPrice(product.avg_competitor_price)}
                  </span>
                </div>
                <div className="flex items-center justify-between mt-1">
                  <span className="text-sm text-gray-500">You save</span>
                  <span className="font-medium text-success-600">
                    {formatPrice(product.avg_competitor_price - product.current_price)}
                  </span>
                </div>
              </div>
            )}
          </div>

          {/* Add to Cart */}
          {isInStock && (
            <div className="bg-white p-6 rounded-lg shadow-soft">
              <div className="flex items-center space-x-4 mb-4">
                <label className="text-sm font-medium text-gray-700">Quantity:</label>
                <div className="flex items-center space-x-2">
                  <button
                    onClick={() => handleQuantityChange(quantity - 1)}
                    className="w-8 h-8 rounded-md border border-gray-300 flex items-center justify-center hover:bg-gray-50 transition-colors"
                  >
                    -
                  </button>
                  <span className="w-12 text-center font-medium">{quantity}</span>
                  <button
                    onClick={() => handleQuantityChange(quantity + 1)}
                    className="w-8 h-8 rounded-md border border-gray-300 flex items-center justify-center hover:bg-gray-50 transition-colors"
                  >
                    +
                  </button>
                </div>
              </div>

              <button
                onClick={handleAddToCart}
                className="w-full flex items-center justify-center space-x-2 px-6 py-3 bg-primary-600 text-white rounded-lg font-medium hover:bg-primary-700 transition-colors"
              >
                <ShoppingCart className="h-5 w-5" />
                <span>Add to Cart</span>
              </button>

              <div className="mt-4 text-center">
                <p className="text-sm text-gray-600">
                  Total: {formatPrice((currentPrice || product.current_price) * quantity)}
                </p>
              </div>
            </div>
          )}

          {/* Features */}
          <div className="grid grid-cols-3 gap-4">
            <div className="text-center p-4 bg-white rounded-lg shadow-soft">
              <Truck className="h-6 w-6 text-primary-600 mx-auto mb-2" />
              <p className="text-xs font-medium text-gray-900">Free Shipping</p>
            </div>
            <div className="text-center p-4 bg-white rounded-lg shadow-soft">
              <Shield className="h-6 w-6 text-primary-600 mx-auto mb-2" />
              <p className="text-xs font-medium text-gray-900">1 Year Warranty</p>
            </div>
            <div className="text-center p-4 bg-white rounded-lg shadow-soft">
              <Clock className="h-6 w-6 text-primary-600 mx-auto mb-2" />
              <p className="text-xs font-medium text-gray-900">24/7 Support</p>
            </div>
          </div>
        </div>
      </div>

      {/* Analytics Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Demand Metrics */}
        {demandMetrics && (
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center space-x-2 mb-4">
              <BarChart3 className="h-5 w-5 text-primary-600" />
              <h2 className="text-xl font-semibold text-gray-900">Demand Analytics</h2>
            </div>

            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <span className="text-sm text-gray-600">Views (last hour)</span>
                <span className="font-medium text-gray-900">{demandMetrics.views_last_hour}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm text-gray-600">Purchases (last hour)</span>
                <span className="font-medium text-gray-900">{demandMetrics.purchases_last_hour}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm text-gray-600">Purchase Rate</span>
                <span className="font-medium text-gray-900">
                  {(demandMetrics.purchase_rate * 100).toFixed(2)}%
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm text-gray-600">Demand Score</span>
                <span className="font-medium text-primary-600">
                  {demandMetrics.demand_score.toFixed(2)}
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Pricing History */}
        {pricingHistory.length > 0 && (
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center space-x-2 mb-4">
              <Clock className="h-5 w-5 text-primary-600" />
              <h2 className="text-xl font-semibold text-gray-900">Recent Price Changes</h2>
            </div>

            <div className="space-y-3">
              {pricingHistory.slice(0, 5).map((change) => (
                <div key={change.id} className="flex items-center justify-between py-2 border-b border-gray-100 last:border-0">
                  <div>
                    <p className="text-sm font-medium text-gray-900">
                      {formatPrice(change.old_price)} → {formatPrice(change.new_price)}
                    </p>
                    <p className="text-xs text-gray-500">{change.reason}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-sm font-medium text-gray-900">
                      {change.new_price > change.old_price ? '+' : ''}
                      {((change.new_price - change.old_price) / change.old_price * 100).toFixed(1)}%
                    </p>
                    <p className="text-xs text-gray-500">
                      {new Date(change.created_at).toLocaleDateString()}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductDetail;
